-- Fix the ID column to allow manual insertion
-- This changes the ID column from GENERATED ALWAYS to GENERATED BY DEFAULT

ALTER TABLE guests ALTER COLUMN id DROP IDENTITY;
ALTER TABLE guests ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;

-- Do the same for check_ins table
ALTER TABLE check_ins ALTER COLUMN id DROP IDENTITY;
ALTER TABLE check_ins ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;
